int userled_lower_initialize(struct userled_lowerhalf_s *lower)
{
  FAR struct userled_upperhalf_s *upper;
  int ret;

  upper = (FAR struct userled_upperhalf_s *)
    kmm_zalloc(sizeof(struct userled_upperhalf_s));

  if (!upper)
    {
      lederr("ERROR: Failed to allocate upper-half state\n");
      return -ENOMEM;
    }

  /* Bind the lower half driver to the upper half driver */

  upper->ul_lower = lower;

  /* Initialize the upper half driver */

