<new_str>#ifdef CONFIG_USERLED_LOWER
/* Upper half driver instance */

static FAR struct userled_upperhalf_s *g_userled_upper;

/****************************************************************************
 * Public Functions
 ****************************************************************************/

/****************************************************************************
 * Name: userled_lower_initialize
 *
 * Description:
 *   Initialize the generic LED lower half driver, bind it and register
 *   it with the upper half LED driver as the user LED driver.
 *
 ****************************************************************************/

int userled_lower_initialize(struct userled_lowerhalf_s *lower)
{
  FAR struct userled_upperhalf_s *upper;
  int ret;

  upper = (FAR struct userled_upperhalf_s *)
    kmm_zalloc(sizeof(struct userled_upperhalf_s));

  if (!upper)
    {
      lederr("ERROR: Failed to allocate upper-half state\n");
      return -ENOMEM;
    }

  /* Bind the lower half driver to the upper half driver */

  upper->ul_lower = lower;

  /* Initialize the upper half driver */

  ret = userled_register(upper);
  if (ret &lt; 0)
    {
      lederr("ERROR: Failed to register upper-half driver: %d\n", ret);
      kmm_free(upper);
      return ret;
    }

  /* Save the upper half driver instance for later uninitialization */

  g_userled_upper = upper;

  return OK;
}

/****************************************************************************
 * Name: userled_lower_uninitialize
 *
 * Description:
 *   Uninitialize the generic LED lower half driver and unregister it
 *   from the upper half LED driver.
 *
 ****************************************************************************/

int userled_lower_uninitialize(void)
{
  if (g_userled_upper)
    {
      /* Unregister the upper half driver */

      userled_unregister(g_userled_upper);

      /* Free the upper half driver instance */

      kmm_free(g_userled_upper);
      g_userled_upper = NULL;
    }

  return OK;
}
#endif</new_str>

