<new_str>/****************************************************************************
 * Private Data
 ****************************************************************************/

static FAR struct userled_dev_s *g_userled_dev;

/****************************************************************************
 * Public Functions
 ****************************************************************************/

/****************************************************************************
 * Name: userled_register
 ****************************************************************************/

int userled_register(FAR struct userled_upperhalf_s *upper)
{
  FAR struct userled_dev_s *priv;
  char devname[DEVNAME_FMTLEN];
  int ret;

  /* Allocate instance data */

  priv = (FAR struct userled_dev_s *)kmm_zalloc(sizeof(struct userled_dev_s));
  if (!priv)
    {
      lederr("ERROR: Failed to allocate private data\n");
      return -ENOMEM;
    }

  /* Initialize the private data */

  priv->led_upper = upper;

  /* Register the character driver */

  snprintf(devname, DEVNAME_FMTLEN, DEVNAME_FMT, 0);
  ret = register_driver(devname, &amp;g_userled_fops, 0666, priv);
  if (ret &lt; 0)
    {
      lederr("ERROR: Failed to register driver: %d\n", ret);
      kmm_free(priv);
      return ret;
    }

  /* Save the device instance for later unregistration */

  g_userled_dev = priv;

  return OK;
}

/****************************************************************************
 * Name: userled_unregister
 *
 * Description:
 *   Unregister the user LED driver and free associated resources.
 *
 ****************************************************************************/

int userled_unregister(FAR struct userled_upperhalf_s *upper)
{
  char devname[DEVNAME_FMTLEN];
  int ret;

  if (g_userled_dev)
    {
      /* Unregister the character driver */

      snprintf(devname, DEVNAME_FMTLEN, DEVNAME_FMT, 0);
      ret = unregister_driver(devname);
      if (ret &lt; 0)
        {
          lederr("ERROR: Failed to unregister driver: %d\n", ret);
          return ret;
        }

      /* Free the private data */

      kmm_free(g_userled_dev);
      g_userled_dev = NULL;
    }

  return OK;
}</new_str>

